firmware_template.source:
#include "thingspeak.h"
#include <WiFi.h>
#include <ThingSpeak.h>
static WiFiClient _client;
static unsigned long _ch=0;
static const char*_key="";
void thingspeak_setup(unsigned long ch,const char*k){_ch=ch;_key=k;ThingSpeak.begin(_client);Serial.printf("[ts] OK ch=%lu\n",ch);}
void thingspeak_set_field(uint8_t f,float v){ThingSpeak.setField(f,v);}
int thingspeak_write(){return ThingSpeak.writeFields(_ch,_key);}
